import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface IndexData {
  name: string;
  currentValue: number;
  change: number;
  changePercent: number;
  sparkline: number[];
}

interface WidgetData {
  indices: IndexData[];
}

export default function Widget() {
  const { indices } = response.data as WidgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#000000' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          {indices.map((index) => {
            const positive = index.change >= 0;
            return (
              <Box key={index.name}>
                <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 0.5 }}>
                  <Box>
                    <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                      {index.name}
                    </Typography>
                    <Typography variant="body1" sx={{ color: '#E5E7EB', fontWeight: 500 }}>
                      {index.currentValue.toFixed(2)}
                    </Typography>
                  </Box>
                  <Box textAlign="right">
                    <Stack direction="row" alignItems="center" spacing={0.5}>
                      {positive ? (
                        <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} />
                      ) : (
                        <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />
                      )}
                      <Typography variant="body2" sx={{ color: positive ? '#10B981' : '#EF4444' }}>
                        {positive ? '+' : ''}
                        {index.change.toFixed(2)} ({index.changePercent.toFixed(2)}%)
                      </Typography>
                    </Stack>
                  </Box>
                </Stack>
                <LineChart
                  height={40}
                  series={[
                    {
                      data: index.sparkline,
                      color: positive ? '#10B981' : '#EF4444',
                      curve: 'natural',
                      showMark: false,
                    },
                  ]}
                  xAxis={[{ data: index.sparkline.map((_, i) => i), hide: true }]}
                  margin={{ top: 5, bottom: 5, left: 0, right: 0 }}
                  sx={{
                    '& .MuiLineElement-root': {
                      strokeWidth: 1.5,
                    },
                  }}
                />
              </Box>
            );
          })}
        </Stack>
      </CardContent>
    </Card>
  );
}
